export const getIssuesControllerGetCommentsByIssueIdUrl = (issueId: string,
    params?: IssuesControllerGetCommentsByIssueIdParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/issues/${issueId}/comments?${stringifiedParams}` : `/api/issues/${issueId}/comments`
}

